'  .hero-sub {',
'    justify-content: center;',
'  }',
'',
'  .section-title {',
'    font-size: 12px;',
'  }',
'}',
'/* -------------------------------------------------------------------------------------------- */',
'/* ------------------- PAGE ITEM DISPLAY ONLY (dark glass value boxes) ------------------- */',
'/* -------------------------------------------------------------------------------------------- */',
'#P2_NOMOR_LAPORAN_DISPLAY,',
'#P2_NAMA_PELAPOR_DISPLAY,',
'#P2_EMAIL_PELAPOR_DISPLAY,',
