'/* -------------------------------------------------------------------------------------------- */',
'/* ------------------- INTERACTIVE GRID (dark liquid glass) ------------------- */',
'/* -------------------------------------------------------------------------------------------- */',
'/* IG region shell - dark glass card (overrides glass-theme light glass) */',
'.t-IRR-region {',
