'}',
'/* Results area transparent so the dark dialog shows through */',
'.a-PopupLOV-results, .a-TMV, .a-TMV-body, .a-TMV-w-scroll {',
'    background: transparent !important;',
'}',
'/* Result list items */',
'.a-PopupLOV-dialog .a-IconList {',
