'}',
'.form-section-header {',
'  padding: 7px 20px 7px 2px;',
'  background: transparent;',
'  font-size: 16px;',
'  font-weight: 700;',
'  color: #eafffb !important;',
'  text-shadow: 0 0 14px rgba(45,212,191,0.4);',
