 p_id=>wwv_flow_imp.id(14344850434666370728)
,p_process_sequence=>20
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'Email to Administrator'
,p_static_id=>'email-to-administrator'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'declare',
'    l_id NUMBER;',
'begin',
'    l_id := apex_mail.send (',
'        -- p_to                 => ''wbs-team@wbs.example.com'',',
'        p_to                 => ''manuelnicholasn@gmail.com'', ',
'        p_bcc                => ''manuelnicholasn@gmail.com'',',
'        -- p_to                 => ''reviewer@wbs.example.com'',',
'        p_from              =>  ''noreply@wbs.example.com'', ',
'        p_template_static_id => ''FORM_RECEIVED'',',
'        p_placeholders       => ''{'' ||',
'        ''    "NOMOR_LAPORAN":''    || apex_json.stringify( :P3_NOMOR_LAPORAN ) ||',
'        -- ''   ,"NAMA_PELAPOR":''        || apex_json.stringify( :P3_NAMA_PELAPOR ) ||',
'        ''   ,"EMAIL_PELAPOR":''       || apex_json.stringify( :P3_EMAIL_PELAPOR ) ||',
'        -- ''   ,"TELP_PELAPOR":''        || apex_json.stringify( :P3_TELP_PELAPOR ) ||',
'        -- ''   ,"TINDAKAN":''            || apex_json.stringify( :P3_TINDAKAN ) ||',
'        -- ''   ,"NAMA_TERLAPOR":''       || apex_json.stringify( :P3_NAMA_TERLAPOR ) ||',
'        -- ''   ,"JABATAN_TERLAPOR":''    || apex_json.stringify( :P3_JABATAN_TERLAPOR ) ||',
'        -- ''   ,"WAKTU_KEJADIAN":''      || apex_json.stringify( :P3_WAKTU_KEJADIAN ) ||',
'        -- ''   ,"LOKASI_KEJADIAN":''     || apex_json.stringify( :P3_LOKASI_KEJADIAN ) ||',
'        -- ''   ,"KRONOLOGIS_KEJADIAN":'' || apex_json.stringify( :P3_KRONOLOGIS_KEJADIAN ) ||',
'        -- ''   ,"NOMINAL":''             || apex_json.stringify( :P3_NOMINAL ) ||',
'        -- ''   ,"FILE":''                || apex_json.stringify( :P3_UPLOAD ) ||',
