wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(14344849691779370721)
,p_process_sequence=>20
,p_parent_process_id=>wwv_flow_imp.id(14344849615798370720)
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'Process Form WBS'
,p_static_id=>'process-form-wbs'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'    v_blob_content BLOB;',
'    v_mime_type VARCHAR2(255);',
'    v_file_name VARCHAR2(500);',
'    v_nomor_laporan VARCHAR2(100);',
'BEGIN',
'    -- Generate NOMOR_LAPORAN',
'    SELECT XTD_WBS_NO.NEXTVAL || ''/IVC/'' || TO_CHAR(SYSDATE, ''RM'') || ''/'' || TO_CHAR(SYSDATE, ''YYYY'')',
'    INTO v_nomor_laporan',
'    FROM DUAL;',
'    ',
'    IF :P3_UPLOAD IS NOT NULL THEN',
'        SELECT BLOB_CONTENT, MIME_TYPE, FILENAME',
'        INTO v_blob_content, v_mime_type, v_file_name',
'        FROM APEX_APPLICATION_TEMP_FILES',
'        WHERE name = :P3_UPLOAD;',
'        ',
'        INSERT INTO XTD_WBS (',
'            ID,',
'            NAMA_PELAPOR,',
'            TELP_PELAPOR,',
'            EMAIL_PELAPOR,',
'            TINDAKAN,',
'            NAMA_TERLAPOR,',
'            JABATAN_TERLAPOR,',
'            WAKTU_KEJADIAN,',
'            LOKASI_KEJADIAN,',
'            KRONOLOGIS_KEJADIAN,',
'            -- NOMINAL,',
'            FILE_BLOB,',
'            MIME_TYPE,',
'            FILE_NAME,',
'            STATUS,',
'            NOMOR_LAPORAN,',
'            PIC',
'        ) VALUES (',
'            XTD_WBS_NO.NEXTVAL,',
'            :P3_NAMA_PELAPOR,',
'            ''+62 '' || :P3_TELP_PELAPOR,',
'            :P3_EMAIL_PELAPOR,',
'            NULL,',
'            :P3_NAMA_TERLAPOR,',
'            :P3_JABATAN_TERLAPOR,',
'            :P3_WAKTU_KEJADIAN,',
'            :P3_LOKASI_KEJADIAN,',
'            :P3_KRONOLOGIS_KEJADIAN,',
'            -- :P3_NOMINAL,',
'            v_blob_content,',
'            v_mime_type,',
'            v_file_name,',
'            :P3_STATUS,',
'            v_nomor_laporan,',
'            :APP_USER',
'        ) RETURNING ID INTO :P3_ID;',
'        ',
'        -- Delete temporary file',
'        DELETE FROM APEX_APPLICATION_TEMP_FILES WHERE name = :P3_UPLOAD;',
'        ',
'    ELSE',
'        -- Insert without file',
'        INSERT INTO XTD_WBS (',
'            ID,',
'            NAMA_PELAPOR,',
'            TELP_PELAPOR,',
'            EMAIL_PELAPOR,',
'            TINDAKAN,',
'            NAMA_TERLAPOR,',
'            JABATAN_TERLAPOR,',
'            WAKTU_KEJADIAN,',
'            LOKASI_KEJADIAN,',
'            KRONOLOGIS_KEJADIAN,',
'            -- NOMINAL,',
'            FILE_BLOB,',
'            MIME_TYPE,',
'            FILE_NAME,',
'            STATUS,',
'            NOMOR_LAPORAN,',
'            PIC',
'        ) VALUES (',
'            XTD_WBS_NO.NEXTVAL,',
'            :P3_NAMA_PELAPOR,',
'            ''+62 '' || :P3_TELP_PELAPOR,',
'            :P3_EMAIL_PELAPOR,',
'            NULL,',
'            :P3_NAMA_TERLAPOR,',
'            :P3_JABATAN_TERLAPOR,',
'            :P3_WAKTU_KEJADIAN,',
'            :P3_LOKASI_KEJADIAN,',
'            :P3_KRONOLOGIS_KEJADIAN,',
'            -- :P3_NOMINAL,',
'            NULL,',
'            NULL,',
'            NULL,',
'            :P3_STATUS,',
'            v_nomor_laporan,',
'            :APP_USER',
'        ) RETURNING ID INTO :P3_ID;',
'        ',
'    END IF;',
'    ',
'    :P3_NOMOR_LAPORAN := v_nomor_laporan;',
'    ',
'EXCEPTION',
'    WHEN OTHERS THEN',
'        IF :P3_UPLOAD IS NOT NULL THEN',
'            DELETE FROM APEX_APPLICATION_TEMP_FILES WHERE name = :P3_UPLOAD;',
'        END IF;',
'        RAISE;',
'END;'))
,p_process_clob_language=>'PLSQL'
,p_process_when_button_id=>wwv_flow_imp.id(14344817031293969524)
,p_process_success_message=>'Your report has been created and submitted successfully.'
,p_required_patch=>wwv_flow_imp.id(14344300039949909298)
,p_internal_uid=>65307812222929005
);
wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(14345424394208289952)
,p_process_sequence=>30
,p_parent_process_id=>wwv_flow_imp.id(14344849615798370720)
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'Process Form WBS (rev.)'
,p_static_id=>'process-form-wbs-rev'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'    v_blob_content BLOB;',
'    v_mime_type VARCHAR2(255);',
'    v_file_name VARCHAR2(500);',
'    v_nomor_laporan VARCHAR2(100);',
'    v_wbs_id NUMBER;',
'    v_temp_name VARCHAR2(2000);',
'    v_file_count NUMBER;',
'BEGIN',
'    -- SELECT XTD_WBS_NO.NEXTVAL || ''/IVC/'' || TO_CHAR(SYSDATE, ''RM'') || ''/'' || TO_CHAR(SYSDATE, ''YYYY'')',
'    -- INTO v_nomor_laporan',
'    -- FROM DUAL;',
'',
'    SELECT ''IVC/'' || TO_CHAR(SYSDATE, ''YYYY'') || ''/'' || LPAD(TO_CHAR(XTD_WBS_NO.NEXTVAL), 4, ''0'')',
'    INTO v_nomor_laporan',
'    FROM DUAL;',
'    ',
'    INSERT INTO XTD_WBS (',
'        ID,',
'        NAMA_PELAPOR,',
'        TELP_PELAPOR,',
'        EMAIL_PELAPOR,',
'        TINDAKAN,',
'        NAMA_TERLAPOR,',
'        JABATAN_TERLAPOR,',
'        WAKTU_KEJADIAN,',
'        LOKASI_KEJADIAN,',
'        KRONOLOGIS_KEJADIAN,',
'        FILE_BLOB,',
'        MIME_TYPE,',
'        FILE_NAME,',
'        STATUS,',
'        NOMOR_LAPORAN,',
'        SOURCE',
'    ) VALUES (',
'        XTD_WBS_NO.NEXTVAL,',
'        :P3_NAMA_PELAPOR,',
'        ''+62 '' || :P3_TELP_PELAPOR,',
'        :P3_EMAIL_PELAPOR,',
'        NULL,',
'        :P3_NAMA_TERLAPOR,',
'        :P3_JABATAN_TERLAPOR,',
'        :P3_WAKTU_KEJADIAN,',
'        :P3_LOKASI_KEJADIAN,',
'        :P3_KRONOLOGIS_KEJADIAN,',
'        NULL, -- FILE_BLOB',
'        NULL, -- MIME_TYPE',
'        NULL, -- FILE_NAME',
'        ''RECEIVED'',',
'        v_nomor_laporan,',
'        ''WEBSITE''',
'    ) RETURNING ID INTO v_wbs_id;',
'    ',
'    :P3_ID := v_wbs_id;',
'    :P3_NOMOR_LAPORAN := v_nomor_laporan;',
'    ',
'    -- Handle multiple file uploads',
'    -- Option 1: using APEX native multiple file upload (colon separated values: ''file1,file2,file3'')',
'    IF :P3_UPLOAD IS NOT NULL AND :P3_UPLOAD != ''[]'' THEN',
'        ',
'        IF :P3_UPLOAD LIKE ''{%'' OR :P3_UPLOAD LIKE ''[%'' THEN',
'            -- Parse JSON array (for APEX 22.2+)',
'            FOR rec IN (',
'                SELECT ',
'                    JSON_VALUE(value, ''$.name'') AS temp_name',
'                FROM JSON_TABLE(:P3_UPLOAD, ''$[*]'' COLUMNS (value VARCHAR2(4000) PATH ''$''))',
'            ) LOOP',
'                SELECT BLOB_CONTENT, MIME_TYPE, FILENAME',
'                INTO v_blob_content, v_mime_type, v_file_name',
'                FROM APEX_APPLICATION_TEMP_FILES',
'                WHERE name = rec.temp_name;',
'                ',
'                INSERT INTO XTD_WBS_BLOB (',
'                    FILE_NAME,',
'                    FILE_MIME_TYPE,',
'                    FILE_BLOB_DATED,',
'                    FILE_BLOB,',
'                    WBS_ID',
'                ) VALUES (',
'                    v_file_name,',
'                    v_mime_type,',
'                    SYSDATE,',
'                    v_blob_content,',
'                    v_wbs_id',
'                );',
'                ',
'                DELETE FROM APEX_APPLICATION_TEMP_FILES WHERE name = rec.temp_name;',
'            END LOOP;',
'        ELSE',
'            -- Option 2: using colon separated values (e.g. ''name1:name2:name3'')',
'            FOR rec IN (',
'                SELECT COLUMN_VALUE AS temp_name',
'                FROM TABLE(APEX_STRING.split(:P3_UPLOAD, '':''))',
'                WHERE COLUMN_VALUE IS NOT NULL',
'            ) LOOP',
'                BEGIN',
'                    SELECT BLOB_CONTENT, MIME_TYPE, FILENAME',
'                    INTO v_blob_content, v_mime_type, v_file_name',
'                    FROM APEX_APPLICATION_TEMP_FILES',
'                    WHERE name = rec.temp_name;',
'                    ',
'                    INSERT INTO XTD_WBS_BLOB (',
'                        FILE_NAME,',
'                        FILE_MIME_TYPE,',
'                        FILE_BLOB_DATED,',
'                        FILE_BLOB,',
'                        WBS_ID',
'                    ) VALUES (',
'                        v_file_name,',
'                        v_mime_type,',
'                        SYSDATE,',
'                        v_blob_content,',
'                        v_wbs_id',
'                    );',
'                    ',
'                    DELETE FROM APEX_APPLICATION_TEMP_FILES WHERE name = rec.temp_name;',
'                EXCEPTION',
'                    WHEN NO_DATA_FOUND THEN',
'                        CONTINUE;',
'                END;',
'            END LOOP;',
'        END IF;',
'    END IF;',
'    ',
'EXCEPTION',
'    WHEN OTHERS THEN',
'        -- IF :P3_UPLOAD IS NOT NULL THEN',
'        --     IF :P3_UPLOAD LIKE ''{%'' OR :P3_UPLOAD LIKE ''[%'' THEN',
'        --         -- If JSON array',
'        --         FOR rec IN (',
'        --             SELECT JSON_VALUE(value, ''$.name'') AS temp_name',
'        --             FROM JSON_TABLE(:P3_UPLOAD, ''$[*]'' COLUMNS (value VARCHAR2(4000) PATH ''$''))',
'        --         ) LOOP',
'        --             DELETE FROM APEX_APPLICATION_TEMP_FILES WHERE name = rec.temp_name;',
'        --         END LOOP;',
'        --     ELSE',
'        --         -- If single or colon separated',
'        --         FOR rec IN (',
'        --             SELECT COLUMN_VALUE AS temp_name',
'        --             FROM TABLE(APEX_STRING.split(:P3_UPLOAD, '':''))',
'        --             WHERE COLUMN_VALUE IS NOT NULL',
'        --         ) LOOP',
'        --             DELETE FROM APEX_APPLICATION_TEMP_FILES WHERE name = rec.temp_name;',
'        --         END LOOP;',
'        --     END IF;',
'        -- END IF;',
'        NULL;',
'        RAISE;',
'END;'))
,p_process_clob_language=>'PLSQL'
,p_process_when_button_id=>wwv_flow_imp.id(14344817031293969524)
,p_process_success_message=>'Your report has been created and submitted successfully.'
,p_internal_uid=>65882514651848236
);
