'BEGIN',
'   l_file_names := apex_string.split (',
'      p_str => :P3_UPLOAD,',
'      p_sep => '':''',
'   );',
'',
'   FOR i IN 1 .. l_file_names.count LOOP',
'      SELECT *',
'      INTO l_file',
'      FROM apex_application_temp_files',
'      WHERE name = l_file_names(i);',
'',
'      INSERT INTO XTD_WBS_BLOB (',
'         FILE_NAME,',
'         FILE_MIME_TYPE,',
'         FILE_BLOB_DATED,',
'         FILE_BLOB,',
'         WBS_ID',
'      ) VALUES (',
'         l_file.filename,',
'         l_file.mime_type,',
'         SYSDATE,',
'         l_file.blob_content,',
'         :P3_ID ',
'      );',
'   END LOOP;',
'END;',
''))
