'}',
'.t-Form-helpButton:hover .icon-help {',
'  color: #2dd4bf;',
'  transform: scale(1.1);',
'}',
'/* Help popup - dark glass like the card */',
'.a-Popup--help {',
'  max-width: 360px;',
'  border-radius: 16px;',
'  box-shadow: 0 20px 40px -12px rgba(0,0,0,0.55);',
