'  background: linear-gradient(160deg, rgba(13,42,45,0.85), rgba(7,24,28,0.92)) !important;',
'  -webkit-backdrop-filter: blur(24px) saturate(1.5);',
'  backdrop-filter: blur(24px) saturate(1.5);',
'}',
'.a-Popup--help .a-Popup-content {',
'  padding: 16px;',
'}',
'.a-Popup--help p {',
