'  border-radius: 10px;',
'}',
'::-webkit-scrollbar-thumb:hover {',
'  background: linear-gradient(135deg, #2dd4bf, #22d3ee);',
'}',
'/* -------------------------------------------------------------------------------------------- */',
'/* ----------------- Responsive Tweaks ----------------- */',
'@media (max-width: 768px) {',
'  .info-banner {',
'    flex-direction: column;',
'    text-align: center;',
'    padding: 20px;',
'  }',
'',
