'    margin: 0 auto;',
'  }',
'',
'  .info-banner .chips {',
'    justify-content: center;',
'  }',
'',
'  .t-Region-bodyWrap {',
'    padding: 10px !important;',
'  }',
'',
'  .form-section-header {',
'    font-size: 14px;',
'  }',
'',
'  .step-num {',
'    width: 22px;',
'    height: 22px;',
'    font-size: 12px;',
'  }',
'',
