'    margin-left: 0;',
'  }',
'',
'  .t-Form-labelContainer {',
'    flex-wrap: wrap;',
'  }',
'',
'  .t-Form-helpButton {',
'    margin-left: auto;',
'  }',
'}',
'@media (max-width: 480px) {',
