'    font-size: 12px;',
'  }',
'',
'  .t-Button-label {',
'    font-size: 13px;',
'  }',
'}',
'/* -------------------------------------------------------------------------------------------- */',
'/* -------------------------------------------------------------------------------------------- */',
'/* ----------------- Page 7 specifics ----------------- */',
'.t-Form-itemRequired {',
'    display: none !important;',
'}',
'.icon-help {',
'    margin-top: 0;',
'}',
'/* -------------------------------------------------------------------------------------------- */',
'/* ------------------- POPUP LOV item (P7_SOURCE) - dark glass ------------------- */',
'.apex-item-group--popup-lov {',
'    display: flex;',
'    align-items: stretch;',
'    background: rgba(7,26,30,0.50) !important;',
