'        KATEGORI_PELANGGARAN = :P4_KATEGORI_PELANGGARAN_VALUE, ',
'        NOTES = :P10_VERIFY_NOTES',
'    WHERE ID = :P4_HEADER_ID;',
'END;'))
,p_process_clob_language=>'PLSQL'
